import { mutationGeneric, queryGeneric } from "convex/server";
import { v } from "convex/values";

export const getParticipantPageData = queryGeneric({
  args: {
    participant_id: v.string(),
  },
  returns: v.union(
    v.null(),
    v.object({
      participant_id: v.string(),
      participant_name: v.string(),
      session_id: v.string(),
      session_location: v.string(),
      session_date: v.string(),
      session_time: v.string(),
      class_name: v.string(),
      qr_code_data: v.string(),
      can_change_session: v.boolean(),
      session_options: v.array(
        v.object({
          session_id: v.string(),
          location: v.string(),
          date: v.string(),
          time: v.string(),
          available_quota: v.number(),
        })
      ),
    })
  ),
  handler: async (ctx, args) => {
    const participant = await ctx.db
      .query("participants")
      .withIndex("by_participant_id", (q) =>
        q.eq("participant_id", args.participant_id)
      )
      .first();

    if (!participant) {
      return null;
    }

    const session = await ctx.db
      .query("sessions")
      .withIndex("by_session_id", (q) => q.eq("session_id", participant.session_id))
      .first();

    if (!session) {
      return null;
    }

    const classRecord = await ctx.db
      .query("classes")
      .withIndex("by_class_id", (q) => q.eq("class_id", session.class_id))
      .first();

    if (!classRecord) {
      return null;
    }

    const canChangeSession = isMoreThanTwoDaysAway(session.date, session.time);

    const availableOptions = canChangeSession
      ? (
          await ctx.db
            .query("sessions")
            .withIndex("by_class_id", (q) => q.eq("class_id", session.class_id))
            .collect()
        )
          .filter((candidateSession) => {
            const availableQuota =
              candidateSession.quota_defined - candidateSession.quota_used;
            return (
              candidateSession.status === "scheduled" &&
              candidateSession.session_id !== session.session_id &&
              availableQuota > 0
            );
          })
          .map((candidateSession) => ({
            session_id: candidateSession.session_id,
            location: candidateSession.location,
            date: candidateSession.date,
            time: candidateSession.time,
            available_quota:
              candidateSession.quota_defined - candidateSession.quota_used,
          }))
          .sort((left, right) =>
            `${left.date}T${left.time}`.localeCompare(`${right.date}T${right.time}`)
          )
      : [];

    return {
      participant_id: participant.participant_id,
      participant_name: participant.name?.trim() || "Participant",
      session_id: session.session_id,
      session_location: session.location,
      session_date: session.date,
      session_time: session.time,
      class_name: classRecord.name,
      qr_code_data: participant.qr_code_data ?? participant.participant_id,
      can_change_session: canChangeSession,
      session_options: availableOptions,
    };
  },
});

export const changeParticipantSession = mutationGeneric({
  args: {
    participant_id: v.string(),
    session_id: v.string(),
  },
  returns: v.object({
    success: v.boolean(),
    error_message: v.optional(v.string()),
  }),
  handler: async (ctx, args) => {
    const participant = await ctx.db
      .query("participants")
      .withIndex("by_participant_id", (q) => q.eq("participant_id", args.participant_id))
      .first();

    if (!participant) {
      return {
        success: false,
        error_message: "Participant was not found.",
      };
    }

    const currentSession = await ctx.db
      .query("sessions")
      .withIndex("by_session_id", (q) => q.eq("session_id", participant.session_id))
      .first();

    if (!currentSession) {
      return {
        success: false,
        error_message: "Current session is not available.",
      };
    }

    if (!isMoreThanTwoDaysAway(currentSession.date, currentSession.time)) {
      return {
        success: false,
        error_message:
          "Session changes are only allowed more than 2 days before the class date.",
      };
    }

    const newSession = await ctx.db
      .query("sessions")
      .withIndex("by_session_id", (q) => q.eq("session_id", args.session_id))
      .first();

    if (!newSession || newSession.status !== "scheduled") {
      return {
        success: false,
        error_message: "Selected session is not available.",
      };
    }

    if (newSession.class_id !== currentSession.class_id) {
      return {
        success: false,
        error_message: "You can only switch to another session of the same class.",
      };
    }

    if (newSession.session_id === currentSession.session_id) {
      return { success: true };
    }

    const newSessionAvailable = newSession.quota_defined - newSession.quota_used;
    if (newSessionAvailable < 1) {
      return {
        success: false,
        error_message: "Selected session is already full.",
      };
    }

    const changedAt = Date.now();

    await ctx.db.patch(participant._id, {
      session_id: newSession.session_id,
    });

    await ctx.db.patch(currentSession._id, {
      quota_used: Math.max(0, currentSession.quota_used - 1),
    });

    await ctx.db.patch(newSession._id, {
      quota_used: newSession.quota_used + 1,
    });

    await ctx.db.insert("audit_logs", {
      action: "participant_session_changed",
      entity_type: "participant",
      entity_id: participant.participant_id,
      metadata: {
        previous_session_id: currentSession.session_id,
        next_session_id: newSession.session_id,
        changed_at: changedAt,
      },
      created_at: changedAt,
    });

    return { success: true };
  },
});

function isMoreThanTwoDaysAway(date: string, time: string): boolean {
  const sessionStartsAt = Date.parse(`${date}T${time}:00`);
  const twoDaysInMs = 2 * 24 * 60 * 60 * 1000;
  return Number.isFinite(sessionStartsAt) && sessionStartsAt - Date.now() > twoDaysInMs;
}

import {
  makeFunctionReference,
  mutationGeneric,
  queryGeneric,
} from "convex/server";
import { v } from "convex/values";

export const getTermsPageData = queryGeneric({
  args: {
    token: v.string(),
  },
  returns: v.union(
    v.null(),
    v.object({
      customer_mobile: v.string(),
      participant_count: v.number(),
      purchase_status: v.union(
        v.literal("pending_terms"),
        v.literal("confirmation_sent"),
        v.literal("terms_accepted"),
        v.literal("cancelled")
      ),
      class_name: v.optional(v.string()),
      terms_version: v.string(),
      terms_content: v.string(),
      sessions: v.array(
        v.object({
          session_id: v.string(),
          class_id: v.string(),
          class_name: v.string(),
          location: v.string(),
          date: v.string(),
          time: v.string(),
          available_quota: v.number(),
        })
      ),
    })
  ),
  handler: async (ctx, args) => {
    const purchase = await ctx.db
      .query("purchases")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();

    if (!purchase || purchase.status === "cancelled") {
      return null;
    }

    const currentTerms = await ctx.db
      .query("terms_versions")
      .withIndex("by_is_current", (q) => q.eq("is_current", true))
      .first();

    if (!currentTerms) {
      return null;
    }

    const classDocs = new Map<string, string>();
    if (purchase.class_id) {
      const purchaseClass = await ctx.db
        .query("classes")
        .withIndex("by_class_id", (q) => q.eq("class_id", purchase.class_id!))
        .first();
      if (purchaseClass) {
        classDocs.set(purchaseClass.class_id, purchaseClass.name);
      }
    }

    const rawSessions = purchase.class_id
      ? await ctx.db
          .query("sessions")
          .withIndex("by_class_id", (q) => q.eq("class_id", purchase.class_id!))
          .collect()
      : await ctx.db.query("sessions").collect();

    const classIds = new Set(rawSessions.map((session) => session.class_id));
    for (const classId of classIds) {
      if (!classDocs.has(classId)) {
        const classRecord = await ctx.db
          .query("classes")
          .withIndex("by_class_id", (q) => q.eq("class_id", classId))
          .first();
        if (classRecord) {
          classDocs.set(classId, classRecord.name);
        }
      }
    }

    const sessions = rawSessions
      .filter((session) => session.status === "scheduled")
      .map((session) => {
        const availableQuota = Math.max(
          session.quota_defined - session.quota_used,
          0
        );
        return {
          session_id: session.session_id,
          class_id: session.class_id,
          class_name: classDocs.get(session.class_id) ?? "Unknown class",
          location: session.location,
          date: session.date,
          time: session.time,
          available_quota: availableQuota,
        };
      })
      .filter((session) => session.available_quota > 0)
      .sort((left, right) => {
        const leftDateTime = `${left.date}T${left.time}`;
        const rightDateTime = `${right.date}T${right.time}`;
        return leftDateTime.localeCompare(rightDateTime);
      });

    return {
      customer_mobile: purchase.customer_mobile,
      participant_count: purchase.participant_count,
      purchase_status: purchase.status,
      class_name: purchase.class_id
        ? (classDocs.get(purchase.class_id) ?? undefined)
        : undefined,
      terms_version: currentTerms.version,
      terms_content: currentTerms.content,
      sessions,
    };
  },
});

export const acceptTermsByToken = mutationGeneric({
  args: {
    token: v.string(),
    session_id: v.string(),
    accepted: v.boolean(),
  },
  returns: v.object({
    success: v.boolean(),
    error_message: v.optional(v.string()),
  }),
  handler: async (ctx, args) => {
    if (!args.accepted) {
      return {
        success: false,
        error_message: "Please accept the terms before submitting.",
      };
    }

    const purchase = await ctx.db
      .query("purchases")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();

    if (!purchase) {
      return {
        success: false,
        error_message: "Purchase token is invalid.",
      };
    }

    if (purchase.status === "terms_accepted") {
      return { success: true };
    }

    if (purchase.status === "cancelled") {
      return {
        success: false,
        error_message: "This purchase has been cancelled.",
      };
    }

    const session = await ctx.db
      .query("sessions")
      .withIndex("by_session_id", (q) => q.eq("session_id", args.session_id))
      .first();

    if (!session || session.status !== "scheduled") {
      return {
        success: false,
        error_message: "Selected session is not available.",
      };
    }

    const slotsRequired = Math.max(1, purchase.participant_count);
    const availableQuota = session.quota_defined - session.quota_used;
    if (availableQuota < slotsRequired) {
      return {
        success: false,
        error_message: "Selected session no longer has enough available quota.",
      };
    }

    const currentTerms = await ctx.db
      .query("terms_versions")
      .withIndex("by_is_current", (q) => q.eq("is_current", true))
      .first();

    if (!currentTerms) {
      return {
        success: false,
        error_message: "No active terms version is available.",
      };
    }

    const acceptedAt = Date.now();

    await ctx.db.patch(purchase._id, {
      class_id: session.class_id,
      session_id: session.session_id,
      status: "terms_accepted",
    });

    await ctx.db.patch(session._id, {
      quota_used: session.quota_used + slotsRequired,
    });

    const participantIds: string[] = [];
    for (let i = 0; i < slotsRequired; i += 1) {
      const participantId = crypto.randomUUID();
      participantIds.push(participantId);

      await ctx.db.insert("participants", {
        participant_id: participantId,
        purchase_id: purchase._id,
        session_id: session.session_id,
        mobile: purchase.customer_mobile,
        qr_code_data: participantId,
        terms_accepted_at: acceptedAt,
        terms_version_id: currentTerms._id,
        created_at: acceptedAt,
      });
    }

    await ctx.scheduler.runAfter(
      0,
      makeFunctionReference<"action">("participantLinks:sendParticipantLinks"),
      {
        customer_mobile: purchase.customer_mobile,
        participant_ids: participantIds,
      }
    );

    await ctx.db.insert("audit_logs", {
      action: "terms_accepted",
      entity_type: "purchase",
      entity_id: purchase.order_id,
      metadata: {
        token: purchase.token,
        session_id: session.session_id,
        class_id: session.class_id,
        accepted_at: acceptedAt,
        terms_version: currentTerms.version,
        participant_ids: participantIds,
      },
      created_at: acceptedAt,
    });

    return { success: true };
  },
});

