type SearchParamValue = string | string[] | undefined;

type AdminLoginPageProps = {
  searchParams: Promise<Record<string, SearchParamValue>>;
};

export default async function AdminLoginPage({ searchParams }: AdminLoginPageProps) {
  const session = await getServerAuthSession();
  if (session?.user?.username) {
    redirect("/admin/dashboard");
  }

  const params = await searchParams;
  const errorMessage = readSingleQueryParam(params.error);

  return (
    <main className="mx-auto flex min-h-screen w-full max-w-md items-center px-4 py-10">
      <section className="w-full rounded-xl border border-zinc-200 bg-white p-6 shadow-sm">
        <h1 className="text-2xl font-semibold text-zinc-900">Admin Login</h1>
        <p className="mt-2 text-sm text-zinc-700">Sign in to access the management portal.</p>
        <LoginForm initialError={errorMessage} />
      </section>
    </main>
  );
}

function readSingleQueryParam(value: SearchParamValue): string | undefined {
  if (typeof value === "string") {
    return value;
  }

  if (Array.isArray(value)) {
    return value[0];
  }

  return undefined;
}

"use client";

import { useState } from "react";
import { signIn } from "next-auth/react";
import { useRouter } from "next/navigation";

type LoginFormProps = {
  initialError?: string;
};

export function LoginForm({ initialError }: LoginFormProps) {
  const router = useRouter();
  const [error, setError] = useState<string | undefined>(initialError);
  const [isSubmitting, setIsSubmitting] = useState(false);

  async function onSubmit(formData: FormData) {
    const username = formData.get("username");
    const password = formData.get("password");

    if (typeof username !== "string" || typeof password !== "string") {
      setError("Please enter a username and password.");
      return;
    }

    setIsSubmitting(true);
    setError(undefined);

    const result = await signIn("credentials", {
      username,
      password,
      redirect: false,
      callbackUrl: "/admin/dashboard",
    });

    setIsSubmitting(false);

    if (!result || result.error) {
      setError("Invalid username or password.");
      return;
    }

    router.push("/admin/dashboard");
    router.refresh();
  }

  return (
    <>
      {error ? (
        <p className="mt-4 rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</p>
      ) : null}

      <form action={onSubmit} className="mt-6 space-y-4">
        <div className="space-y-1">
          <label htmlFor="username" className="text-sm font-medium text-zinc-900">
            Username
          </label>
          <input
            id="username"
            name="username"
            type="text"
            autoComplete="username"
            required
            className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm text-zinc-900 outline-none ring-zinc-900/10 focus:border-zinc-400 focus:ring"
          />
        </div>

        <div className="space-y-1">
          <label htmlFor="password" className="text-sm font-medium text-zinc-900">
            Password
          </label>
          <input
            id="password"
            name="password"
            type="password"
            autoComplete="current-password"
            required
            className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm text-zinc-900 outline-none ring-zinc-900/10 focus:border-zinc-400 focus:ring"
          />
        </div>

        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full rounded-md bg-zinc-900 px-4 py-2 text-sm font-medium text-white transition hover:bg-zinc-800 disabled:cursor-not-allowed disabled:opacity-60"
        >
          {isSubmitting ? "Signing in..." : "Sign In"}
        </button>
      </form>
    </>
  );
}

import { ConvexHttpClient } from "convex/browser";
import { makeFunctionReference } from "convex/server";
import type { NextAuthOptions } from "next-auth";
import { getServerSession } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";

type AdminRole = "super_admin" | "regular_admin";

export const authOptions: NextAuthOptions = {
  session: {
    strategy: "jwt",
  },
  pages: {
    signIn: "/admin/login",
  },
  providers: [
    CredentialsProvider({
      name: "Admin Login",
      credentials: {
        username: { label: "Username", type: "text" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        const username =
          typeof credentials?.username === "string"
            ? credentials.username.trim()
            : "";
        const password =
          typeof credentials?.password === "string" ? credentials.password : "";

        if (username.length === 0 || password.length === 0) {
          return null;
        }

        const convexUrl =
          process.env.NEXT_PUBLIC_CONVEX_URL ??
          process.env.CONVEX_URL ??
          process.env.NEXT_CONVEX_URL;
        if (!convexUrl) {
          return null;
        }

        try {
          const client = new ConvexHttpClient(
            convexUrl.trim().replace(/\/+$/, ""),
            { logger: false }
          );
          const result = await client.action(
            makeFunctionReference<"action">("adminAuth:validateAdminCredentials"),
            {
              username,
              password,
            }
          );

          if (!result.success || !result.username || !result.role) {
            return null;
          }

          return {
            id: result.username,
            name: result.username,
            username: result.username,
            role: result.role,
          };
        } catch {
          return null;
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.username = user.username;
        token.role = user.role as AdminRole;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user && token.username && token.role) {
        session.user.username = token.username;
        session.user.role = token.role as AdminRole;
        session.user.name = token.username;
      }
      return session;
    },
  },
};

export function getServerAuthSession() {
  return getServerSession(authOptions);
}

import { ConvexHttpClient } from "convex/browser";

export function createConvexHttpClient() {
  const deploymentUrl = resolveConvexDeploymentUrl();
  return new ConvexHttpClient(deploymentUrl, { logger: false });
}

function resolveConvexDeploymentUrl(): string {
  const fromEnv =
    process.env.NEXT_PUBLIC_CONVEX_URL ??
    process.env.CONVEX_URL ??
    process.env.NEXT_CONVEX_URL;

  if (!fromEnv) {
    throw new Error(
      "Missing Convex URL. Set NEXT_PUBLIC_CONVEX_URL (or CONVEX_URL) to your deployment URL."
    );
  }

  return fromEnv.trim().replace(/\/+$/, "");
}

